def solve(*args, **kwargs):
    import json
    import os

    # Extract problemId from args or kwargs
    # Assuming the first positional argument is problemId
    if args:
        problem_id = args[0]
    else:
        problem_id = kwargs.get('problemId')
    if not problem_id:
        # No problemId provided, return 404 JSON error
        return {
            "status": 404,
            "error": "Problem ID not provided"
        }

    # Load problems.json data
    base_dir = os.path.dirname(os.path.abspath(__file__))
    data_path = os.path.join(base_dir, '..', '..', 'data', 'problems.json')
    try:
        with open(data_path, 'r', encoding='utf-8') as f:
            problems_data = json.load(f)
    except Exception:
        # If file not found or invalid JSON, return 404 error
        return {
            "status": 404,
            "error": "Problems data not found or invalid"
        }

    # Find the problem by problem_id
    problem = None
    for p in problems_data.get('problems', []):
        if str(p.get('problemId')) == str(problem_id):
            problem = p
            break

    if not problem:
        # Problem not found, return 404 JSON error
        return {
            "status": 404,
            "error": "Problem not found"
        }

    # Aggregate component metadata
    components = problem.get('components', [])
    language_counts = {}
    status_counts = {}
    max_points = 0

    for comp in components:
        lang = comp.get('language')
        if lang:
            language_counts[lang] = language_counts.get(lang, 0) + 1

        status = comp.get('status')
        if status:
            status_counts[status] = status_counts.get(status, 0) + 1

        points = comp.get('points', 0)
        if isinstance(points, (int, float)) and points > max_points:
            max_points = points

    # Return problem data with aggregated metadata
    result = {
        "problemId": problem.get('problemId'),
        "name": problem.get('name'),
        "components": components,
        "languageCounts": language_counts,
        "statusCounts": status_counts,
        "maxPoints": max_points
    }

    return result
